n = int(input())
words = []
for i in range(n):
    word = input()
    if len(set(word)) <= 2:
        words.append(word)

lengths = []
for i in range(len(words)):
    for j in range(i+1, len(words)):
        combined = words[i] + words[j]
        if len(set(combined)) <= 2:
            lengths.append(len(combined))

if lengths:
    print(max(lengths))
else:
    print(0)
